import math
import pygame
import time

# 修改后的配色方案
COLOR_S, COLOR_E = 100, 255  # 更宽的亮度范围
COLOR_BG = (20, 20, 40)     # 深蓝色背景

def ortho(_p, left, right, bottom, top):
    _x, _y, z = _p
    new_x = (2 * _x - right - left) / (right - left)
    new_y = (2 * _y - top - bottom) / (top - bottom)
    return new_x, new_y, z

def rotate_x(vector, angle_rad):
    """
    绕X轴旋转三维向量
    :param vector: 三维向量 [x, y, z]
    :param angle_rad: 旋转角度（弧度）
    :return: 旋转后的新向量 [x', y', z']
    """
    _x, _y, _z = vector
    cos_theta = math.cos(angle_rad)
    sin_theta = math.sin(angle_rad)
    y_new = _y * cos_theta - _z * sin_theta
    z_new = _y * sin_theta + _z * cos_theta
    return [_x, y_new, z_new]

def rotate_y(vector, angle_rad):
    """
    绕Y轴旋转三维向量
    :param vector: 三维向量 [x, y, z]
    :param angle_rad: 旋转角度（弧度）
    :return: 旋转后的新向量 [x', y', z']
    """
    x, y, z = vector
    cos_theta = math.cos(angle_rad)
    sin_theta = math.sin(angle_rad)
    x_new = x * cos_theta + z * sin_theta
    z_new = -x * sin_theta + z * cos_theta
    return [x_new, y, z_new]

def transform(p, t):
    angle_rad = math.radians(-90 * t)
    return ortho(rotate_y(rotate_x(p, angle_rad), 0.2 * math.sin(t * math.pi)), -5, 5, -5, 5)

def render(surface, model, t, scale, tx, ty):
    t = 4 * t * t * t if t < 0.5 else 1 - pow(-2 * t + 2, 3) / 2

    ps = [(transform(p[0], t), p[1]) for p in model]
    ps.sort(key=lambda p:p[0][2])
    for p in ps:
        pygame.draw.circle(surface, p[1], ((tx+scale*p[0][0]), (ty+scale*p[0][1])), 10)

def add_color(p):
    x, y, z = p
    per_x, per_y, per_z = (x + 5) / 10, (y + 5) / 10, (z + 5) / 10
    s, e = COLOR_S, COLOR_E
    return p, (s + (e - s) * per_x, s + (e - s) * per_y, s + (e - s) * per_z)

